+// Constructor
+GazeboRosOpenniKinect::GazeboRosOpenniKinect()
+{
+  this->point_cloud_connect_count_ = 0;
+  this->depth_info_connect_count_ = 0;
+  this->last_depth_image_camera_info_update_time_ = common::Time(0);
