+////////////////////////////////////////////////////////////////////////////////
+// Destructor
+GazeboRosRange::~GazeboRosRange()
+{
+  this->range_queue_.clear();
+  this->range_queue_.disable();
+  this->rosnode_->shutdown();
+  this->callback_queue_thread_.join();
+
+  delete this->rosnode_;
+}
